let input = $('Получение данных для арки').first().json.summary
let report = "";
if (input == null) return { text: null };

// Форматирование для ГЛАВЫ
// Форматирование для АРКИ
report = `### ТЕКУЩЕЕ СОСТОЯНИЕ АРКИ\n`;
report += `${input.arc_summary_rolling}\n\n`;
report += `**Основной конфликт:** ${input.main_conflict}\n`;
report += `**Цели героев:** ${input.goals.join("; ")}\n`;
report += `**Ключевые изменения:** ${input.key_changes.join("; ")}\n`;
report += `**Открытые вопросы:** ${input.open_threads.join("; ")}`;

return { text: report };
